#include<bits/stdc++.h>
using namespace std;
int b[100010],val[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,sum;
        long long lson,rson;
        long long add_tag,mul_tag;
        node():add_tag(0),mul_tag(1){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void clear()
    {
        cnt=0;
    }
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long ad=a[x].add_tag,mu=a[x].mul_tag;
        a[ls].sum=(a[ls].sum*mu+(mid-a[x].l+1)*ad);
        a[rs].sum=(a[rs].sum*mu+(a[x].r-mid)*ad);
        a[ls].mul_tag=(a[ls].mul_tag*mu);
        a[rs].mul_tag=(a[rs].mul_tag*mu);
        a[ls].add_tag=(a[ls].add_tag*mu+ad);
        a[rs].add_tag=(a[rs].add_tag*mu+ad);
        a[x].add_tag=0;
        a[x].mul_tag=1;
    }
    long long init1(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].add_tag=0;
        a[x].mul_tag=1;
        if(l==r)
        {
            a[x].sum=b[l];
            return x;
        }
        a[x].lson=init1(l,mid);
        a[x].rson=init1(mid+1,r);
        pushup(x);
        return x;
    }
    void init(long long n)
    {
        init1(1,n);
    }
    void add1(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum+((a[x].r-a[x].l+1)*z));
            a[x].add_tag=(a[x].add_tag+z);
            return;
        }
        pushdown(x);
        add1(a[x].lson,l,r,z);
        add1(a[x].rson,l,r,z);
        pushup(x);
    }
    void add(long long l,long long r,long long x)
    {
        add1(1,l,r,x);
    }
    void mul1(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum*z);
            a[x].add_tag=(a[x].add_tag*z);
            a[x].mul_tag=(a[x].mul_tag*z);
            return;
        }
        pushdown(x);
        mul1(a[x].lson,l,r,z);
        mul1(a[x].rson,l,r,z);
        pushup(x);
    }
    void mul(long long l,long long r,long long x)
    {
        mul1(1,l,r,x);
    }
    long long getsum1(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum1(a[x].lson,l,r)+getsum1(a[x].rson,l,r));
    }
    long long getsum(long long l,long long r)
    {
        return getsum1(1,l,r);
    }
    void update(long long l,long long r,long long v)
    {
        mul(l,r,0);
        add(l,r,v);
    }
}t;
int op[100010],l[100010],r[100010],n,m,q;
bool check(int x)
{
    t.clear();
    for(int i=1;i<=n;i++)
    {
        if(val[i]>=x)
        {
            b[i]=1;
        }
        else
        {
            b[i]=0;
        }
    }
    t.init(n);
    for(int i=1;i<=m;i++)
    {
        if(op[i]==0)
        {
            int len=r[i]-l[i]+1;
            int p=t.getsum(l[i],r[i]);
            t.update(l[i],l[i]+(len-p)-1,0);
            t.update(l[i]+(len-p),r[i],1);
        }
        else
        {
            int len=r[i]-l[i]+1;
            int p=t.getsum(l[i],r[i]);
            t.update(l[i],l[i]+p-1,1);
            t.update(l[i]+p,r[i],0);
        }
    }
    return t.getsum(q,q)==1;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&op[i],&l[i],&r[i]);
    }
    scanf("%d",&q);
    int l=1,r=n,best=-1;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            best=mid;
            l=mid+1;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%d",best);
    return 0;
}
